class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> result = new ArrayList<>();
        backtrack(n, k, 0, result, 0);
        int[] ans = new int[result.size()];
        for (int i = 0; i < result.size(); i++) {
            ans[i] = result.get(i);
        }
        return ans;
    }
    private void backtrack(int n, int k, int current, List<Integer> result, int prev) {
        if (n == 0) {
            result.add(current);
            return;
        }
        int next = prev + k;
        if (next >= 0 && next <= 9) {
            backtrack(n - 1, k, current * 10 + next, result, next);
        }
        next = prev - k;
        if (next >= 0 && next <= 9) {
            backtrack(n - 1, k, current * 10 + next, result, next);
        }
    }
}
